// requireAuth extracts auth claims from context or returns an error.
// Returns a GraphQL error with extensions.code = "UNAUTHENTICATED" so clients
// can detect auth failures in GraphQL responses (not just HTTP 401).
func requireAuth(ctx context.Context) (*auth.Claims, error) {
	claims := auth.GetClaims(ctx)
	if claims == nil {
		return nil, &gqlerror.Error{
			Message:    "authentication required",
			Extensions: map[string]any{"code": "UNAUTHENTICATED"},
		}
	}
	return claims, nil
}

